import{_ as d,aa as n,o as r,c as a,a as e,V as i,U as y,Y as s}from"./chunks/framework.D4G4v7Gb.js";import"./chunks/theme.Cupgy2ZJ.js";const f=JSON.parse('{"title":"Drone-Runner 环境变量","description":"Drone Docker Runner 全部环境变量参考手册，涵盖资源配置、RPC 连接、管道限制和外部插件集成等核心参数的中文翻译说明","frontmatter":{"title":"Drone-Runner 环境变量","category":["Drone"],"tag":["环境变量","Runner","Docker","参考手册"],"description":"Drone Docker Runner 全部环境变量参考手册，涵盖资源配置、RPC 连接、管道限制和外部插件集成等核心参数的中文翻译说明","date":"2022-07-25T15:33:28.000Z","updated":"2022-07-25T15:33:28.000Z","cover":"https://docs.drone.io/logo.svg"},"headers":[],"relativePath":"articles/devops/ci-cd/drone/drone-runner-env.md","filePath":"articles/devops/ci-cd/drone/drone-runner-env.md"}'),x={name:"articles/devops/ci-cd/drone/drone-runner-env.md"};function g(E,t,_,R,c,h){const l=n("SmallCard");return r(),a("div",null,[t[0]||(t[0]=e("h2",{id:"参考资料",tabindex:"-1"},[i("参考资料 "),e("a",{class:"header-anchor",href:"#参考资料","aria-label":"Permalink to “参考资料”"},"​")],-1)),y(l,{cards:[{title:"Reference Index of server configuration settings",desc:"Drone is a self-service Continuous Integration platform for busy development teams.",logo:"https://docs.drone.io/logo.svg",link:"https://docs.drone.io/runner/docker/configuration/reference/"}]}),t[1]||(t[1]=s('<h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li>文档翻译为<a href="https://www.deepl.com" target="_blank" rel="noreferrer">Deepl</a>机翻。</li><li>默认值：无，仅表示翻译过程中并未直接指出该环境变量的值是什么。</li><li>此翻译，仅供参数。</li><li>docker镜像版本为<code>drone/drone-runner-docker:1</code>下环境变量解释。</li></ol><h2 id="环境变量" tabindex="-1">环境变量 <a class="header-anchor" href="#环境变量" aria-label="Permalink to “环境变量”">​</a></h2><ol><li><p>DRONE_CPU_PERIOD</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CPU_PERIOD</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的整数值。指定CPU CFS调度器的周期，与CPU配额一起使用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CPU_PERIOD=100000</td></tr></tbody></table></li><li><p>DRONE_CPU_QUOTA</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CPU_QUOTA</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的整数值。对所有管道容器施加一个CPU CFS配额。容器在节流之前，每一个CPU周期的微秒数限制。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CPU_QUOTA=100</td></tr></tbody></table></li><li><p>DRONE_CPU_SET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CPU_SET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的字符串值。限制一个管道容器可以使用的特定CPU或核心。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CPU_SET=1,3</td></tr></tbody></table></li><li><p>DRONE_CPU_SHARES</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_CPU_SHARES</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的整数值。将此标志设置为大于或小于默认值1024的值，以增加或减少管道容器的重量，并使其能够获得更大或更小比例的主机CPU周期。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_CPU_SHARES=1024</td></tr></tbody></table></li><li><p>DRONE_DEBUG</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DEBUG</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。启用调试级别的日志记录。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DEBUG=true</td></tr></tbody></table></li><li><p>DRONE_DEFER_TAIL_LOG</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DEFER_TAIL_LOG</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。启用新的日志生命周期，以帮助防止日志被截断。在1.8.1版本中可用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DEFER_TAIL_LOG=true</td></tr></tbody></table></li><li><p>DRONE_DOCKER_CONFIG</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DOCKER_CONFIG</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供Docker config.json文件的路径，用于从第三方系统中获取注册表的凭证。 <strong>请注意，你通常需要把这个文件从主机装入你的Docker容器。注意上面定义的配置路径应该指向容器内的文件路径。</strong></td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DOCKER_CONFIG=/root/.docker/config.json docker run --volume /root/.docker/config.json:/root/.docker/config.json</td></tr></tbody></table></li><li><p>DRONE_DOCKER_NETWORK_ID</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DOCKER_NETWORK_ID</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。指定要创建的docker网络的名称。默认情况下，它是一个随机字符串。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DOCKER_NETWORK_ID=named_network</td></tr></tbody></table></li><li><p>DRONE_DOCKER_STREAM_PULL</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_DOCKER_STREAM_PULL</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。禁止将Docker pull的输出写到构建日志中。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">true</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_DOCKER_STREAM_PULL=true</td></tr></tbody></table></li><li><p>DRONE_ENV_PLUGIN_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_ENV_PLUGIN_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供用于向外部环境变量插件发出http请求的端点。外部环境变量插件可用于从第三方系统获取自定义管道环境变量。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_ENV_PLUGIN_ENDPOINT=<code>http://1.2.3.4:3000</code></td></tr></tbody></table></li><li><p>DRONE_ENV_PLUGIN_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_ENV_PLUGIN_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。在向插件端点发出http请求时禁用SSL验证。这是不安全的，不推荐。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_ENV_PLUGIN_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_ENV_PLUGIN_TOKEN</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_ENV_PLUGIN_TOKEN</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供用于验证对插件端点的http请求的秘密令牌。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_ENV_PLUGIN_TOKEN=bea26a2221fd8090ea38720fc445eca6</td></tr></tbody></table></li><li><p>DRONE_HTTP_BIND</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_HTTP_BIND</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值用于配置http监听器的端口。默认值是:3000。不建议重写这个值。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">3000</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_HTTP_BIND=:3000</td></tr></tbody></table></li><li><p>DRONE_HTTP_HOST</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_HTTP_HOST</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值，用于配置http监听器的主机名。默认值是一个空字符串。不建议设置此值。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;"><code>&quot;&quot;</code></td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_HTTP_HOST=runner.company.com:3000</td></tr></tbody></table></li><li><p>DRONE_HTTP_PROTO</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_HTTP_PROTO</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值用于配置http监听器协议。默认值是http。不建议重写这个值。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">http</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_HTTP_PROTO=http</td></tr></tbody></table></li><li><p>DRONE_LIMIT_EVENTS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LIMIT_EVENTS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的字符串值。提供可由该运行器处理的构建事件的白名单。这提供了一个额外的安全层，以限制该运行器可以处理的工作负载的种类。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LIMIT_EVENTS=push,tag</td></tr></tbody></table></li><li><p>DRONE_LIMIT_REPOS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LIMIT_REPOS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的字符串值。配置运行器，使其只处理匹配的存储库。这提供了一个额外的安全层，可以阻止不受信任的存储库使用该运行器执行管道。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LIMIT_REPOS=octocat/hello-world,spaceghost/*</td></tr></tbody></table></li><li><p>DRONE_LIMIT_TRUSTED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_LIMIT_TRUSTED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。配置运行器，使其只处理受信任的存储库。这提供了一个额外的安全层，可以阻止不受信任的存储库与该运行器一起执行管道。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_LIMIT_TRUSTED=true</td></tr></tbody></table></li><li><p>DRONE_MEMORY_LIMIT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_MEMORY_LIMIT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的整数值。单个流水线容器可以使用的最大内存量，以字节为单位配置。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_MEMORY_LIMIT=500000000</td></tr></tbody></table></li><li><p>DRONE_MEMORY_SWAP_LIMIT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_MEMORY_SWAP_LIMIT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的整数值。允许单个流水线容器交换到磁盘的最大内存量，以字节为单位进行配置。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_MEMORY_SWAP_LIMIT=500000000</td></tr></tbody></table></li><li><p>DRONE_NETRC_CLONE_ONLY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_NETRC_CLONE_ONLY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。配置运行器，使其仅在克隆步骤中注入克隆凭证。<strong>请注意，如果版本库是私有的或需要认证才能克隆，Drone 会将克隆凭证注入所有管道步骤；如果版本库是公共的，Drone 不会将凭证注入管道步骤。</strong></td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_NETRC_CLONE_ONLY=true</td></tr></tbody></table></li><li><p>DRONE_REGISTRY_PLUGIN_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_REGISTRY_PLUGIN_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供用于向外部注册表插件发出http请求的端点。外部注册表插件可用于从第三方系统获取注册表凭证。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_REGISTRY_PLUGIN_ENDPOINT=<code>http://1.2.3.4:3000</code></td></tr></tbody></table></li><li><p>DRONE_REGISTRY_PLUGIN_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_REGISTRY_PLUGIN_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。在向注册表插件端点发出http请求时禁用SSL验证。这是不安全的，不推荐。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_REGISTRY_PLUGIN_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_REGISTRY_PLUGIN_TOKEN</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_REGISTRY_PLUGIN_TOKEN</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供用于验证对注册表插件端点的http请求的令牌。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_REGISTRY_PLUGIN_TOKEN=bea26a2221fd8090ea38720fc445eca6</td></tr></tbody></table></li><li><p>DRONE_RPC_DUMP_HTTP</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_DUMP_HTTP</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。启用将http请求和响应转储到日志中的功能，以便进行调试。这应该只在调试运行器和服务器之间的连接问题时启用</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_DUMP_HTTP=true</td></tr></tbody></table></li><li><p>DRONE_RPC_DUMP_HTTP_BODY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_DUMP_HTTP_BODY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。启用将http请求和响应体转储到日志中以进行调试。这应该只在调试运行器和服务器之间的连接问题时启用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_DUMP_HTTP_BODY=true</td></tr></tbody></table></li><li><p>DRONE_RPC_HOST</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_HOST</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">必要的字符串值。定义用于连接Drone服务器的主机名（和可选端口）。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_HOST=drone.company.com</td></tr></tbody></table></li><li><p>DRONE_RPC_PROTO</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_PROTO</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">必要的字符串值。定义用于连接Drone服务器的协议。该值必须是 http 或 https。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_PROTO=https</td></tr></tbody></table></li><li><p>DRONE_RPC_SECRET</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_SECRET</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">必要的字符串值。提供Drone服务器用于验证http请求的共享秘密。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_SECRET=bea26a2221fd8090ea38720fc445eca6</td></tr></tbody></table></li><li><p>DRONE_RPC_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RPC_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。在向Drone服务器发出http请求时禁用SSL验证。这是不安全的，不建议使用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RPC_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_RUNNER_CAPACITY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_CAPACITY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的数字值。限制运行器可以执行的并发管线的数量。运行器默认执行2条并发管道。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">2</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_CAPACITY=10</td></tr></tbody></table></li><li><p>DRONE_RUNNER_CLONE_IMAGE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_CLONE_IMAGE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。覆盖用于克隆版本库的Docker镜像。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_CLONE_IMAGE=drone/git:1</td></tr></tbody></table></li><li><p>DRONE_RUNNER_DEVICES</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_DEVICES</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的列表。提供被安装到每个管道步骤中的设备的列表。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_DEVICES=/dev/sdb</td></tr></tbody></table></li><li><p>DRONE_RUNNER_ENV_FILE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_ENV_FILE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供环境变量文件的路径，用于定义注入所有管道步骤中的全局环境变量。<a href="https://github.com/joho/godotenv/blob/main/README.md" target="_blank" rel="noreferrer">这里记录了环境文件的格式</a>。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_ENV_FILE=/etc/drone.conf 记住要把这个文件从主机装入Docker容器。注意上面定义的配置路径应该指向容器内的文件路径。 docker run --volume /etc/drone.conf:/etc/drone.conf</td></tr></tbody></table></li><li><p>DRONE_RUNNER_ENVIRON</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_ENVIRON</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串映射。提供一组注入到每个管道步骤的全局环境变量。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_ENVIRON=foo:bar,baz:qux</td></tr></tbody></table></li><li><p>DRONE_RUNNER_LABELS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_LABELS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串映射。提供一组标签，用于将管道路由到特定机器或一组机器。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_LABELS=foo:bar,baz:qux</td></tr></tbody></table></li><li><p>DRONE_RUNNER_MAX_PROCS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_MAX_PROCS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的数字值。限制一个运行器可以为一个管道执行的并发步骤的数量。这在默认情况下是禁用的。如果你需要节制最大的并行步骤数量以防止资源耗尽，这可能是有用的。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">0</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_MAX_PROCS=10</td></tr></tbody></table></li><li><p>DRONE_RUNNER_NAME</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_NAME</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。设置运行器的名称。跑步者的名字存储在服务器中，可以用来追溯到一个特定的跑步者。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_NAME=ec2-43-21.us-east-1.compute.amazonaws.com</td></tr></tbody></table></li><li><p>DRONE_RUNNER_NETWORKS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_NETWORKS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的列表。提供连接到每个管道步骤的Docker网络的列表。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_NETWORKS=networkA,networkB</td></tr></tbody></table></li><li><p>DRONE_RUNNER_PRIVILEGED_IMAGES</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_PRIVILEGED_IMAGES</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的列表。提供一个默认作为特权容器启动的Docker镜像的列表。<strong>特权模式有效地授予容器对主机的根权限。请慎重使用</strong></td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_PRIVILEGED_IMAGES=plugins/docker,plugin/ecr</td></tr></tbody></table></li><li><p>DRONE_RUNNER_SECRETS</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_SECRETS</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串映射。提供一组全局的、命名的秘密，供所有管道使用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_SECRETS=username:bar,password:qux</td></tr></tbody></table></li><li><p>DRONE_RUNNER_VOLUMES</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_RUNNER_VOLUMES</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的逗号分隔的列表。提供挂载到每个管道步骤中的Docker卷的列表。在下面的例子中，冒号左边的路径是主机的路径。右边的路径是你的管道容器内的路径</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_RUNNER_VOLUMES=/path/on/host:/path/in/container</td></tr></tbody></table></li><li><p>DRONE_SECRET_PLUGIN_ENDPOINT</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SECRET_PLUGIN_ENDPOINT</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供用于向外部秘密插件发出http请求的端点。外部秘密插件（如vault）可用于从第三方系统获取秘密。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SECRET_PLUGIN_ENDPOINT=<code>http://1.2.3.4:3000</code></td></tr></tbody></table></li><li><p>DRONE_SECRET_PLUGIN_SKIP_VERIFY</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SECRET_PLUGIN_SKIP_VERIFY</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。在向插件端点发出http请求时禁用SSL验证。这是不安全的，不推荐。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SECRET_PLUGIN_SKIP_VERIFY=false</td></tr></tbody></table></li><li><p>DRONE_SECRET_PLUGIN_TOKEN</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_SECRET_PLUGIN_TOKEN</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。提供用于验证对插件端点的http请求的秘密令牌。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_SECRET_PLUGIN_TOKEN=bea26a2221fd8090ea38720fc445eca6</td></tr></tbody></table></li><li><p>DRONE_TMATE_ENABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_TMATE_ENABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。启用使用tmate的管道容器的远程ssh访问。托管服务和自我托管服务都被支持。这个功能默认是禁用的。这个功能需要1.6.1版本的docker runner和更高版本。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">false</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_TMATE_ENABLED=true 请注意，你也可以使用下面的配置参数来配置一个自我托管的tmate服务器。请参阅官方的tmate文档以了解更多关于自我托管tmate服务器的信息。 <code>DRONE_TMATE_ENABLED=true</code> <code>DRONE_TMATE_HOST=tmate.company.com</code> <code>DRONE_TMATE_PORT=2200</code> <code>DRONE_TMATE_FINGERPRINT_RSA=SHA256:iL3StSCmPU+7p2IoD8y0huMXRVFIZyGFZa8r+lO3U5I</code> <code>DRONE_TMATE_FINGERPRINT_ED25519=SHA256:gXLaN8IUxUMmlm/xu7M2NEFMlbUr5UORUgMi86Kh+tI</code></td></tr></tbody></table></li><li><p>DRONE_TRACE</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_TRACE</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。启用跟踪级别的日志记录。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_TRACE=true</td></tr></tbody></table></li><li><p>DRONE_UI_DISABLED</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_UI_DISABLED</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的布尔值。禁用运行器的用户界面。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_UI_DISABLE=true</td></tr></tbody></table></li><li><p>DRONE_UI_PASSWORD</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_UI_PASSWORD</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。设置基本认证密码，用于认证和访问网络仪表板。如果没有提供密码，网络仪表板将被禁用。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_UI_PASSWORD=root</td></tr></tbody></table></li><li><p>DRONE_UI_REALM</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_UI_REALM</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。设置用于验证和访问网络仪表板的基本认证境界。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_UI_REALM=DroneRealm</td></tr></tbody></table></li><li><p>DRONE_UI_USERNAME</p><table tabindex="0"><thead><tr><th style="text-align:center;">描述</th><th style="text-align:left;">定义</th></tr></thead><tbody><tr><td style="text-align:center;">环境变量</td><td style="text-align:left;">DRONE_UI_USERNAME</td></tr><tr><td style="text-align:center;">解释</td><td style="text-align:left;">可选的字符串值。设置用于验证和访问网络仪表板的基本认证用户名。</td></tr><tr><td style="text-align:center;">默认值</td><td style="text-align:left;">无</td></tr><tr><td style="text-align:center;">示例</td><td style="text-align:left;">DRONE_UI_USERNAME=root</td></tr></tbody></table></li></ol>',4))])}const b=d(x,[["render",g]]);export{f as __pageData,b as default};
